"use client";

/**
 * <CashFlowProjection> — daily projected-cash line over a 30/60/90-day horizon
 * with event markers, a low-point pinch, today + end nodes, and a runway floor.
 *
 * Tier-2 per CHART-STANDARD §5.1. viewBox === real px width via useChartSize.
 */

import { useMemo } from "react";
import { useChartSize } from "@/lib/useChartSize";
import { ChartStates, type ChartState } from "./_kit/ChartStates";

export interface CashLineModel {
  start: number;
  end: number;
  low: number;
  lowDay: number;
  horizonMax: number;
  floor: number;
}

export interface CashFlowMarker {
  day: number;
  code: string;
  t: "in" | "out";
  amt: string;
}

export interface CashFlowProjectionProps {
  model?: CashLineModel;
  events?: CashFlowMarker[];
  /** Days into the future the projection should render (clamped to model.horizonMax). */
  horizon?: number;
  state?: ChartState;
  onLowClick?: () => void;
  /** y-axis bounds. Pass derived from your data; defaults work for the sample. */
  yMin?: number;
  yMax?: number;
  /** Label used in empty/error copy. */
  label?: string;
}

export const sampleCashLineModel: CashLineModel = {
  start: 860000,
  end: 1020000,
  low: 312000,
  lowDay: 47,
  horizonMax: 90,
  floor: 280000,
};

export const sampleCashFlowMarkers: CashFlowMarker[] = [
  { day: 1, code: "STRIPE", t: "in", amt: "+$68K" },
  { day: 9, code: "PAYROLL", t: "out", amt: "−$45K" },
  { day: 22, code: "SETTLEMENT", t: "in", amt: "+$56K" },
  { day: 28, code: "TAX", t: "out", amt: "−$81K" },
  { day: 55, code: "SUPPLIERS", t: "out", amt: "−$92K" },
];

const fmtK = (v: number) => "$" + Math.round(v / 1000) + "K";

export function CashFlowProjection({
  model = sampleCashLineModel,
  events = sampleCashFlowMarkers,
  horizon: rawHorizon = 90,
  state = "ready",
  onLowClick,
  yMin = 240000,
  yMax = 1100000,
  label = "Cash projection",
}: CashFlowProjectionProps) {
  const horizon = Math.max(1, Math.min(rawHorizon, model.horizonMax));
  const { ref, width } = useChartSize({ min: 560, fallback: 1180 });
  const VB_W = Math.max(560, width);
  const VB_H = 260;
  const padL = 72;
  const padR = 34;
  const padT = 30;
  const padB = 30;
  const plotW = VB_W - padL - padR;
  const plotH = VB_H - padT - padB;
  const base = padT + plotH;

  const valAt = (d: number) => {
    const { start, low, lowDay, end, horizonMax } = model;
    if (d <= lowDay) return start + (low - start) * (d / lowDay);
    return low + (end - low) * ((d - lowDay) / (horizonMax - lowDay));
  };

  const xPos = (d: number) => padL + (d / horizon) * plotW;
  const yPos = (v: number) =>
    padT + (1 - (Math.max(yMin, Math.min(yMax, v)) - yMin) / (yMax - yMin)) * plotH;

  const wpAll = [0, 13, 26, 39, model.lowDay, 60, 73, 86, 90];
  const wp = wpAll.filter((d) => d <= horizon);
  if (wp[wp.length - 1] !== horizon) wp.push(horizon);
  const pts = wp.map((d) => ({ d, x: xPos(d), y: yPos(valAt(d)) }));
  const lowInView = model.lowDay <= horizon;
  const lx = xPos(model.lowDay);
  const ly = yPos(model.low);

  const visibleEvents = events.filter((e) => e.day <= horizon);
  const endVal = valAt(horizon);
  const floorY = yPos(model.floor);
  const polyline = pts.map((p) => `${p.x.toFixed(1)},${p.y.toFixed(1)}`).join(" ");
  const areaPath =
    `M ${padL} ${base} L ${pts[0].x.toFixed(1)} ${pts[0].y.toFixed(1)} ` +
    pts.slice(1).map((p) => `L ${p.x.toFixed(1)} ${p.y.toFixed(1)}`).join(" ") +
    ` L ${pts[pts.length - 1].x.toFixed(1)} ${base} Z`;

  const visibleEventDays = useMemo(
    () => new Set(visibleEvents.map((e) => e.day)),
    [visibleEvents],
  );

  return (
    <div className="cfp-wrap">
      <div className="cfp-head">
        <div className="cfp-kicker">Projected cash position · daily</div>
        <div className="cfp-readout">
          <div className="v">{fmtK(endVal)}</div>
          <div className="k">at day {horizon}</div>
        </div>
      </div>
      <div ref={ref}>
        <ChartStates state={state} height={VB_H} label={label}>
          <svg className="cfp-svg" viewBox={`0 0 ${VB_W} ${VB_H}`}>
            <defs>
              <linearGradient id="cfp-grad" x1="0" y1="0" x2="0" y2="1">
                <stop offset="0" stopColor="var(--d-finance)" stopOpacity="0.16" />
                <stop offset="1" stopColor="var(--d-finance)" stopOpacity="0" />
              </linearGradient>
            </defs>
            {[400000, 600000, 800000, 1000000].map((v) => (
              <g key={v}>
                <line className="cfp-grid" x1={padL} y1={yPos(v)} x2={VB_W - padR} y2={yPos(v)} />
                <text className="cfp-ylabel" x={padL - 8} y={yPos(v) + 3} textAnchor="end">
                  ${(v / 1_000_000).toFixed(1)}M
                </text>
              </g>
            ))}
            <line className="cfp-floor" x1={padL} y1={floorY} x2={VB_W - padR} y2={floorY} />
            <text className="cfp-floor-label" x={padL + 2} y={floorY - 6}>
              RUNWAY FLOOR · {fmtK(model.floor)}
            </text>

            <path d={areaPath} fill="url(#cfp-grad)" />
            <polyline className="cfp-line" points={polyline} />

            {pts.slice(1, -1).map((p, i) => {
              const dwp = wp[i + 1];
              if (Math.abs(p.x - lx) < 6) return null;
              if (visibleEventDays.has(dwp)) return null;
              return (
                <rect
                  key={i}
                  className="cfp-dot"
                  x={p.x - 3.5}
                  y={p.y - 3.5}
                  width={7}
                  height={7}
                  rx={1}
                />
              );
            })}

            {visibleEvents.map((e) => {
              const ex = xPos(e.day);
              const ey = yPos(valAt(e.day));
              const above = e.t === "in";
              const labY = above ? ey - 22 : ey + 26;
              return (
                <g key={e.code}>
                  <line className="cfp-ev-stem" x1={ex} y1={ey} x2={ex} y2={above ? labY + 4 : labY - 12} />
                  <text className="cfp-ev-code" x={ex} y={labY} textAnchor="middle">{e.code}</text>
                  <text className={`cfp-ev-amt ${e.t}`} x={ex} y={labY + 11} textAnchor="middle">{e.amt}</text>
                  <rect className={`cfp-ev-node ${e.t}`} x={ex - 5.5} y={ey - 5.5} width={11} height={11} rx={1.5} />
                </g>
              );
            })}

            {lowInView && (
              <>
                <rect
                  className="cfp-dot-low"
                  x={lx - 6}
                  y={ly - 6}
                  width={12}
                  height={12}
                  rx={1.5}
                  onClick={onLowClick}
                  style={onLowClick ? { cursor: "pointer" } : undefined}
                />
                <text className="cfp-low-val" x={lx} y={ly + 26} textAnchor="middle">
                  {fmtK(model.low)} low · day {model.lowDay}
                </text>
              </>
            )}

            <rect className="cfp-today" x={pts[0].x - 5} y={pts[0].y - 5} width={10} height={10} rx={1.5} />
            <rect
              className="cfp-end"
              x={pts[pts.length - 1].x - 5}
              y={pts[pts.length - 1].y - 5}
              width={10}
              height={10}
              rx={1.5}
            />
            <text
              className="cfp-end-val"
              x={pts[pts.length - 1].x}
              y={pts[pts.length - 1].y - 14}
              textAnchor="end"
            >
              {fmtK(endVal)}
            </text>
          </svg>
        </ChartStates>
      </div>
    </div>
  );
}
