/**
 * Mock data for the Finance · Cash Flow sub-page.
 *
 * - FCF carve: free cash flow vs holds vs inventory (what's profit on paper
 *   vs what's actually in the bank).
 * - 30-day events ledger drives both the timeline and the chart markers.
 * - 90-day cash line is modeled with a dip at day 47 (low point) before
 *   recovering to ~$1.02M by day 90.
 */

export type CashFlowDir = "in" | "out";
export type CashFlowTag = "inflow" | "supplier" | "recurring" | "tax" | "pinch";

export interface CashFlowEvent {
  day: number;
  when: string;
  name: string;
  tag: CashFlowTag;
  amount: number; // signed; +inflow / -outflow
  /** running balance after this event */
  balAfter: number;
  /** flagged as the low-point pinch */
  low?: boolean;
}

const START_CASH = 860_000;
const RAW_EVENTS: Array<Omit<CashFlowEvent, "balAfter">> = [
  { day: 1, when: "Tomorrow", name: "Stripe payout", tag: "inflow", amount: 68200 },
  { day: 2, when: "In 2 days", name: "PayPal transfer", tag: "inflow", amount: 38400 },
  { day: 3, when: "In 3 days", name: "Supplier — Northwind", tag: "supplier", amount: -28000 },
  { day: 4, when: "In 4 days", name: "Supplier — Acme Parts", tag: "supplier", amount: -24000 },
  { day: 6, when: "In 6 days", name: "Supplier — BrightBox", tag: "supplier", amount: -15000 },
  { day: 12, when: "Day 12", name: "Payroll", tag: "recurring", amount: -45000 },
  { day: 15, when: "Day 15", name: "Rent + utilities", tag: "recurring", amount: -21000 },
  { day: 18, when: "Day 18", name: "SaaS + logistics", tag: "recurring", amount: -12400 },
  { day: 22, when: "Day 22", name: "PayPal settlement", tag: "inflow", amount: 55800 },
  { day: 28, when: "Day 28", name: "Quarterly tax payment", tag: "tax", amount: -80540 },
  { day: 47, when: "Day 47", name: "Supplier batch + tax", tag: "pinch", amount: -92000, low: true },
];

let bal = START_CASH;
export const CASH_EVENTS: CashFlowEvent[] = RAW_EVENTS.map((e) => {
  bal += e.amount;
  return { ...e, balAfter: bal };
});

