"use client";

import { useState } from "react";
import { DeptHeader } from "@/components/shared/DeptHeader";
import { AIStrip } from "@/components/shared/AIStrip";
import { PeriodTabs } from "@/components/shared/PeriodTabs";
import { SectionLabel } from "@/components/shared/SectionLabel";
import { BridgePrimaryButton } from "@/features/bridge/components/BridgePrimaryButton";
import { CashFlowProjection } from "@/components/charts/CashFlowProjection";
import "@/components/charts/CashFlowProjection.css";
import {
  CASH_EVENTS,
  fcfCarve,
  cashFlowKpis,
  cashLineModel,
  chartEvents,
  cashFlowAI,
} from "@/features/finance/api/finance-cashflow-data";
import "./cashflow.css";

const fmtK = (v: number) => {
  const a = Math.abs(v);
  if (a >= 1_000_000) return `$${(a / 1_000_000).toFixed(2)}M`;
  return `$${Math.round(a / 1000)}K`;
};
const fmtUSD = (v: number) => `$${Math.round(v).toLocaleString()}`;
const fmtSign = (v: number) => `${v >= 0 ? "+" : "−"}$${Math.abs(Math.round(v)).toLocaleString()}`;

const HORIZONS = [30, 60, 90];
const HORIZON_LABELS = ["30 days", "60 days", "90 days"];

export default function CashFlowPage() {
  const [horizonIdx, setHorizonIdx] = useState(2);
  const horizon = HORIZONS[horizonIdx];
  const [selectedDay, setSelectedDay] = useState<number | null>(null);

  // FCF carve %s — denominator is profit (cash + holds + inventory = profit)
  const carveTotal = fcfCarve.profit;
  const cashPct = (fcfCarve.freeCashFlow / carveTotal) * 100;
  const holdsPct = (fcfCarve.holds / carveTotal) * 100;
  const invPct = (fcfCarve.inventory / carveTotal) * 100;

  const tlNet = CASH_EVENTS.filter((e) => e.day <= 28).reduce((a, e) => a + e.amount, 0);

  return (
    <div className="finance-cashflow-page">
      <DeptHeader
        dept="finance"
        title="Cash Flow"
        meta={
          <>
            <span className="live">Live</span> · Cash generated vs profit · from orders + ledger + providers
          </>
        }
        actions={
          <>
            <button className="btn-util">Export</button>
            <BridgePrimaryButton dept="finance">Plan a payment →</BridgePrimaryButton>
          </>
        }
      />

      <PeriodTabs labels={HORIZON_LABELS} activeIndex={horizonIdx} onChange={setHorizonIdx} />

      <AIStrip label={cashFlowAI.label} meta={cashFlowAI.meta} cards={cashFlowAI.cards} />

      {/* FCF (profit vs cash) hero */}
      <SectionLabel>Profit vs cash — what you earned vs what actually landed</SectionLabel>
      <div className="fcf">
        <div className="fcf-head">
          <div className="fcf-headline">
            <div className="rbig">{fmtK(fcfCarve.freeCashFlow)}</div>
            <div className="rlbl">
              Free cash flow
              <br />actually generated
              <span className="delta">↑ $19K vs last quarter</span>
            </div>
          </div>
          <div className="fcf-of">
            <div className="k">reported net profit</div>
            <div className="v">{fmtK(fcfCarve.profit)}</div>
          </div>
        </div>

        <div className="fcf-carve">
          <div className="fcf-seg cash" style={{ width: `${cashPct.toFixed(1)}%` }}>
            <span className="sv">{fmtK(fcfCarve.freeCashFlow)} cash</span>
            <span className="sk">free to spend</span>
          </div>
          <div className="fcf-seg holds" style={{ width: `${holdsPct.toFixed(1)}%` }}>
            <span className="sv">{fmtK(fcfCarve.holds)}</span>
            <span className="sk">Holds</span>
          </div>
          <div className="fcf-seg inventory" style={{ width: `${invPct.toFixed(1)}%` }}>
            <span className="sv">{fmtK(fcfCarve.inventory)}</span>
            <span className="sk">Inventory</span>
          </div>
          <div className="cut" style={{ left: `${cashPct.toFixed(1)}%` }} />
        </div>

        <div className="fcf-legend">
          <span className="li cash"><i />Free cash flow</span>
          <span className="li holds"><i />Gateway holds</span>
          <span className="li inventory"><i />Inventory</span>
        </div>

        <div className="fcf-line">
          Profit is an accounting story; cash is what you can spend. The slice to the right of the line is <b>profit you &ldquo;earned&rdquo; but can&rsquo;t touch yet</b> — which is how a profitable store still misses payroll.
        </div>
      </div>

      {/* KPI band */}
      <div className="cf-kpis">
        {cashFlowKpis.map((k, i) => (
          <div key={i} className="cf-kpi">
            <div className="l">{k.label}</div>
            <div className={`v ${k.color || ""}`}>
              {k.value}
              {k.unit && (
                <span style={{ fontSize: 15, color: "var(--ink-3)" }}> {k.unit}</span>
              )}
            </div>
            <div className="s">{k.sub}</div>
          </div>
        ))}
      </div>

      {/* 90-day projection — <CashFlowProjection> Tier-2 chart */}
      <SectionLabel>Next 90 days — where the cash line goes</SectionLabel>
      <CashFlowProjection
        model={cashLineModel}
        events={chartEvents}
        horizon={horizon}
        onLowClick={() => setSelectedDay(cashLineModel.lowDay)}
      />
      <div className="forecast-axis">
        <span>Today</span>
        <span>+{Math.round(horizon / 3)} days</span>
        <span>+{Math.round((horizon / 3) * 2)} days</span>
        <span className="end">+{horizon} days</span>
      </div>
      <div className="forecast-read">
        <b>You dip to $312K on day 47</b> — a supplier batch and the quarterly tax payment land together — then recover to $1.02M by day 90. The floor holds; no action needed, but that week is the one to watch.
      </div>

      {/* Timeline + CCC sidebar */}
      <SectionLabel>Next 30 days — every cash event</SectionLabel>
      <div className="timeline-wrap">
        <div className="timeline">
          {CASH_EVENTS.filter((e) => e.day <= 28).map((e) => (
            <div
              key={e.day + e.name}
              className={`tl-row${selectedDay === e.day ? " sel" : ""}`}
              onClick={() => setSelectedDay((cur) => (cur === e.day ? null : e.day))}
            >
              <span className="date">{e.when}</span>
              <span className="desc">
                {e.name}
                <span className="tag">{e.tag}</span>
              </span>
              <span className={`amt ${e.amount > 0 ? "in" : "out"}`}>
                {fmtSign(e.amount)}
              </span>
            </div>
          ))}
          <div className="tl-foot">
            <span className="k">Net over 30 days</span>
            <span className="v" style={{ color: "var(--loss)" }}>
              {fmtSign(tlNet)}
            </span>
          </div>
        </div>

        <div className="cf-side">
          <div className="ccc">
            <div className="ccc-label">Cash conversion cycle</div>
            <div className="ccc-big">
              34 <small>days</small>
            </div>
            <div className="ccc-bench">
              Category typical: 25–35 days <span className="est">· modeled estimate</span>
              <br />You&rsquo;re in range, lengthening from 28.
            </div>
            <div className="ccc-steps">
              <div className="ccc-step">
                <div className="sv">48</div>
                <div className="sk">days inventory</div>
              </div>
              <div className="ccc-step minus">
                <div className="sv">+6</div>
                <div className="sk">days to collect</div>
              </div>
              <div className="ccc-step minus">
                <div className="sv">−20</div>
                <div className="sk">days to pay</div>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Stash unused for now */}
      {selectedDay && <span style={{ display: "none" }}>{fmtUSD(selectedDay)}</span>}
    </div>
  );
}
